import type { ReactNode } from "react";
import { Header } from "@/components/headers/header";
import { ScrollArea } from "@/components/ui/scroll-area";
import { getDocsNavigation } from "@/lib/docs";
import { DocsSidebar } from "./_components/docs-sidebar";
import "./styles.css";
import { routes } from "@/config/routes";

interface DocsLayoutProps {
  children: ReactNode;
}

export default async function DocsLayout({ children }: DocsLayoutProps) {
  const navigation = await getDocsNavigation();
  const navLinks = [
    { href: routes.docs, label: "Docs" },
    { href: routes.features, label: "Features" },
    { href: routes.pricing, label: "Pricing" },
  ];

  return (
    <>
      <Header navLinks={navLinks} variant="sticky" />
      <div className="flex-1 items-start md:grid md:grid-cols-[220px_minmax(0,1fr)_220px] lg:grid-cols-[256px_minmax(0,1fr)_256px]">
        {/* Sidebar */}
        <aside className="fixed top-14 z-30 -ml-2 hidden h-[calc(100vh-3.5rem)] w-full shrink-0 overflow-y-auto border-r md:sticky md:block">
          <ScrollArea className="h-full py-6">
            <div className="pl-8 pr-6 lg:pl-10">
              <DocsSidebar navigation={navigation} />
            </div>
          </ScrollArea>
        </aside>

        {/* Main content */}
        <main className="relative py-6 lg:py-8 container mx-auto w-full min-w-0">
          {/* Content */}
          {children}
        </main>
      </div>
    </>
  );
}

import type { Metadata } from "next";
import { notFound } from "next/navigation";
import { MDXRemote } from "next-mdx-remote/rsc";
import { Suspense } from "react";
import remarkGfm from "remark-gfm";
import { SuspenseFallback } from "@/components/primitives/suspense-fallback";
import { constructMetadata } from "@/config/metadata";
import { siteConfig } from "@/config/site-config";
import { getAllDocSlugsFromFileSystem, getDocFromParams } from "@/lib/docs";
import { getMDXComponents } from "@/mdx-components";

interface PageProps {
  params: Promise<{
    slug: string[];
  }>;
}

export async function generateStaticParams() {
  const slugs = await getAllDocSlugsFromFileSystem();

  return slugs.map((slug: string) => {
    // For the index page, return empty array for slug
    if (slug === "index") {
      return { slug: [] };
    }
    // For other pages, split the slug into segments
    return { slug: slug.split("/") };
  });
}

export async function generateMetadata({ params }: PageProps): Promise<Metadata> {
  const defaultMetadata = constructMetadata({
    title: `Documentation - Build Better Apps Faster | ${siteConfig.title}`,
    description: `Master app development with ${siteConfig.title}'s comprehensive documentation. Step-by-step guides, API references, and best practices for building production-ready applications.`,
    openGraph: {
      type: "article",
      siteName: `${siteConfig.title} Documentation`,
      locale: "en_US",
    },
  });

  try {
    const doc = await getDocFromParams(params);

    if (!doc) {
      return defaultMetadata;
    }

    return constructMetadata({
      title: `${doc.title} - ${siteConfig.title} Documentation`,
      description:
        doc.description ||
        `Learn how to implement ${siteConfig.title} features and best practices in your app development workflow. Detailed guides and examples included.`,
      openGraph: {
        type: "article",
        siteName: `${siteConfig.title} Documentation`,
        title: doc.title,
        description: doc.description,
        locale: "en_US",
      },
    });
  } catch (error) {
    return defaultMetadata;
  }
}

export default async function DocsPage({ params }: PageProps) {
  const doc = await getDocFromParams(params);

  if (!doc?.content) {
    notFound();
  }

  return (
    <article className="docs-content">
      <Suspense fallback={<SuspenseFallback />}>
        <MDXRemote
          source={doc.content}
          components={getMDXComponents({})}
          options={{ mdxOptions: { remarkPlugins: [remarkGfm] } }}
        />
      </Suspense>
    </article>
  );
}

import { redirect } from "next/navigation";
import { routes } from "@/config/routes";

export default function NotFound() {
  // Use a temporary redirect (307) to send all docs 404s to the docs home
  // This preserves method and is appropriate for dynamic content that may change
  redirect(routes.docs);
}

