"use client";

import { DialogTitle } from "@radix-ui/react-dialog";
import {
  ChevronRightIcon,
  ClockIcon,
  FileTextIcon,
  MagnifyingGlassIcon,
} from "@radix-ui/react-icons";
import { useRouter } from "next/navigation";
import { useCallback, useEffect, useRef, useState } from "react";
import { Badge } from "@/components/ui/badge";
import {
  CommandDialog,
  CommandEmpty,
  CommandGroup,
  CommandInput,
  CommandItem,
  CommandList,
  CommandLoading,
} from "@/components/ui/command";
import { Input } from "@/components/ui/input";
import { Skeleton } from "@/components/ui/skeleton";
import { routes } from "@/config/routes";
import { type DocSearchResult, useDocsSearch } from "@/hooks/use-docs-search";
import { cn } from "@/lib/utils";

// Popular docs for initial suggestions
const POPULAR_DOCS = [
  {
    title: "Introduction",
    url: `${routes.docs}/introduction`,
    description: "Get started with Shipkit",
  },
  {
    title: "Quickstart Guide",
    url: `${routes.docs}/quickstart`,
    description: "Quick setup and deployment",
  },
  {
    title: "Authentication",
    url: `${routes.docs}/auth`,
    description: "User authentication and authorization",
  },
  {
    title: "Database",
    url: `${routes.docs}/database`,
    description: "Database setup and configuration",
  },
  {
    title: "Deployment",
    url: `${routes.docs}/deployment`,
    description: "Deploy your application",
  },
];

// Recent searches storage key
const RECENT_SEARCHES_KEY = "docs-recent-searches";
const MAX_RECENT_SEARCHES = 5;

export function DocsSearch() {
  const router = useRouter();
  const [open, setOpen] = useState(false);
  const [selectedIndex, setSelectedIndex] = useState(0);
  const [recentSearches, setRecentSearches] = useState<string[]>([]);
  const inputRef = useRef<HTMLInputElement>(null);

  const { query, setQuery, results, isLoading, error, search, clearResults, hasSearched } =
    useDocsSearch({
      debounceDelay: 300,
      minQueryLength: 1,
      limit: 8,
    });

  // Load recent searches from localStorage
  useEffect(() => {
    try {
      const stored = localStorage.getItem(RECENT_SEARCHES_KEY);
      if (stored) {
        setRecentSearches(JSON.parse(stored));
      }
    } catch (error) {
      console.warn("Failed to load recent searches:", error);
    }
  }, []);

  // Save search to recent searches
  const saveToRecentSearches = useCallback((searchQuery: string) => {
    if (!searchQuery.trim()) return;

    try {
      setRecentSearches((prev) => {
        const updated = [searchQuery, ...prev.filter((s) => s !== searchQuery)].slice(
          0,
          MAX_RECENT_SEARCHES
        );
        localStorage.setItem(RECENT_SEARCHES_KEY, JSON.stringify(updated));
        return updated;
      });
    } catch (error) {
      console.warn("Failed to save recent search:", error);
    }
  }, []);

  // Get current items for display (results, popular docs, or recent searches)
  const currentItems = hasSearched ? results : [];
  const showPopularDocs = !hasSearched && !query.trim();
  const showRecentSearches = !hasSearched && query.trim() && recentSearches.length > 0;

  // Calculate total items for keyboard navigation
  const totalItems =
    currentItems.length +
    (showPopularDocs ? POPULAR_DOCS.length : 0) +
    (showRecentSearches ? recentSearches.length : 0);

  // Reset selection when items change
  useEffect(() => {
    setSelectedIndex(0);
  }, [totalItems, query]);

  // Handle command execution
  const runCommand = useCallback((command: () => unknown) => {
    setOpen(false);
    command();
  }, []);

  // Handle search result navigation
  const handleResultSelect = useCallback(
    (result: DocSearchResult) => {
      saveToRecentSearches(query);
      runCommand(() => router.push(result.url));
    },
    [query, saveToRecentSearches, runCommand, router]
  );

  // Handle popular doc navigation
  const handlePopularDocSelect = useCallback(
    (doc: (typeof POPULAR_DOCS)[0]) => {
      runCommand(() => router.push(doc.url));
    },
    [runCommand, router]
  );

  // Handle recent search selection
  const handleRecentSearchSelect = useCallback(
    (recentQuery: string) => {
      setQuery(recentQuery);
      void search(recentQuery);
    },
    [setQuery, search]
  );

  // Keyboard navigation
  const handleKeyDown = useCallback(
    (e: React.KeyboardEvent) => {
      if (!open) return;

      switch (e.key) {
        case "ArrowDown":
          e.preventDefault();
          setSelectedIndex((prev) => (prev + 1) % Math.max(1, totalItems));
          break;
        case "ArrowUp":
          e.preventDefault();
          setSelectedIndex((prev) => (prev === 0 ? totalItems - 1 : prev - 1));
          break;
        case "Enter": {
          e.preventDefault();
          if (totalItems === 0) return;

          // Determine which item is selected
          let currentIndex = 0;

          // Check search results
          if (selectedIndex < currentItems.length && currentItems[selectedIndex]) {
            handleResultSelect(currentItems[selectedIndex]);
            return;
          }
          currentIndex += currentItems.length;

          // Check popular docs
          if (showPopularDocs && selectedIndex < currentIndex + POPULAR_DOCS.length) {
            const docIndex = selectedIndex - currentIndex;
            if (POPULAR_DOCS[docIndex]) {
              handlePopularDocSelect(POPULAR_DOCS[docIndex]);
              return;
            }
          }
          currentIndex += showPopularDocs ? POPULAR_DOCS.length : 0;

          // Check recent searches
          if (showRecentSearches && selectedIndex < currentIndex + recentSearches.length) {
            const recentIndex = selectedIndex - currentIndex;
            if (recentSearches[recentIndex]) {
              handleRecentSearchSelect(recentSearches[recentIndex]);
              return;
            }
          }
          break;
        }
        case "Escape":
          setOpen(false);
          break;
      }
    },
    [
      open,
      totalItems,
      selectedIndex,
      currentItems,
      showPopularDocs,
      showRecentSearches,
      recentSearches,
      handleResultSelect,
      handlePopularDocSelect,
      handleRecentSearchSelect,
    ]
  );

  // Handle dialog open/close
  const handleOpenChange = useCallback(
    (newOpen: boolean) => {
      setOpen(newOpen);
      if (!newOpen) {
        clearResults();
        setSelectedIndex(0);
      } else {
        // Focus input when dialog opens
        setTimeout(() => inputRef.current?.focus(), 0);
      }
    },
    [clearResults]
  );

  // Render search result item
  const renderSearchResult = (result: DocSearchResult, index: number) => {
    const isSelected = selectedIndex === index;

    return (
      <CommandItem
        key={`result-${index}`}
        value={`result-${result.title}-${index}`}
        onSelect={() => handleResultSelect(result)}
        className={cn("flex items-start gap-3 p-3 cursor-pointer", isSelected && "bg-accent")}
      >
        <FileTextIcon className="h-4 w-4 mt-0.5 text-muted-foreground flex-shrink-0" />
        <div className="flex-1 min-w-0">
          <div className="flex items-center gap-2">
            <span className="font-medium text-sm truncate">{result.title}</span>
            {result.section && (
              <Badge variant="outline" className="text-xs">
                {result.section}
              </Badge>
            )}
          </div>
          <p className="text-xs text-muted-foreground mt-1 line-clamp-2">{result.content}</p>
        </div>
        <ChevronRightIcon className="h-3 w-3 text-muted-foreground flex-shrink-0" />
      </CommandItem>
    );
  };

  // Render popular doc item
  const renderPopularDoc = (doc: (typeof POPULAR_DOCS)[0], index: number) => {
    const isSelected = selectedIndex === currentItems.length + index;

    return (
      <CommandItem
        key={`popular-${index}`}
        value={`popular-${doc.title}-${index}`}
        onSelect={() => handlePopularDocSelect(doc)}
        className={cn("flex items-center gap-3 p-3 cursor-pointer", isSelected && "bg-accent")}
      >
        <FileTextIcon className="h-4 w-4 text-muted-foreground" />
        <div className="flex-1">
          <span className="font-medium text-sm">{doc.title}</span>
          <p className="text-xs text-muted-foreground">{doc.description}</p>
        </div>
      </CommandItem>
    );
  };

  // Render recent search item
  const renderRecentSearch = (recentQuery: string, index: number) => {
    const isSelected = selectedIndex === currentItems.length + index;

    return (
      <CommandItem
        key={`recent-${index}`}
        value={`recent-${recentQuery}-${index}`}
        onSelect={() => handleRecentSearchSelect(recentQuery)}
        className={cn("flex items-center gap-3 p-3 cursor-pointer", isSelected && "bg-accent")}
      >
        <ClockIcon className="h-4 w-4 text-muted-foreground" />
        <span className="text-sm">{recentQuery}</span>
      </CommandItem>
    );
  };

  return (
    <>
      <div className="relative w-full">
        <MagnifyingGlassIcon className="absolute left-2 top-3 h-4 w-4 text-muted-foreground" />
        <Input
          className="h-9 w-full rounded-[0.5rem] bg-background pl-8 text-sm text-muted-foreground"
          placeholder="Search docs..."
          onClick={() => setOpen(true)}
          readOnly
        />
      </div>

      <CommandDialog open={open} onOpenChange={handleOpenChange}>
        <div className="w-full h-[300px] flex flex-col">
          <DialogTitle className="sr-only">Search Documentation</DialogTitle>
          <CommandInput
            ref={inputRef}
            placeholder="Type to search documentation..."
            value={query}
            onValueChange={setQuery}
            onKeyDown={handleKeyDown}
          />
          <CommandList className="flex-1 overflow-y-auto">
            {isLoading && (
              <div className="p-4 text-center text-sm text-muted-foreground">Searching...</div>
            )}

            {error && (
              <div className="p-4 text-center">
                <p className="text-sm text-destructive">{error}</p>
              </div>
            )}

            {!isLoading && !error && hasSearched && results.length === 0 && (
              <CommandEmpty>No results found for "{query}"</CommandEmpty>
            )}

            {/* Search Results */}
            {!isLoading && results.length > 0 && (
              <CommandGroup heading="Documentation">
                {results.map((result, index) => renderSearchResult(result, index))}
              </CommandGroup>
            )}

            {/* Popular Documentation */}
            {!isLoading && showPopularDocs && (
              <CommandGroup heading="Popular Documentation">
                {POPULAR_DOCS.map((doc, index) => renderPopularDoc(doc, index))}
              </CommandGroup>
            )}

            {/* Recent Searches */}
            {!isLoading && showRecentSearches && (
              <CommandGroup heading="Recent Searches">
                {recentSearches.map((recentQuery, index) => renderRecentSearch(recentQuery, index))}
              </CommandGroup>
            )}
          </CommandList>
        </div>
      </CommandDialog>
    </>
  );
}

import fs from "fs";
import matter from "gray-matter";
import path from "path";
import { cache } from "react";
import { z } from "zod";

export const DocSchema = z.object({
  title: z.string().min(1).max(500), // Increased from 200 to 500
  description: z.string().max(1000).optional(), // Made optional, increased from 500 to 1000
  slug: z.string().min(1).max(200), // Increased from 100 to 200
  content: z.string(),
  keywords: z.array(z.string().max(100)).optional(), // Increased from 50 to 100
  author: z.string().max(200).optional(), // Increased from 100 to 200
  publishedAt: z.string().datetime().optional(),
  updatedAt: z.string().datetime().optional(),
  lastModified: z.date().optional(),
  section: z.string().max(100).default("core"), // Changed from enum to flexible string with default
  seo: z
    .object({
      canonicalUrl: z.string().url().optional(),
      focusKeywords: z.array(z.string().max(100)).optional(), // Increased from 50 to 100
      metaRobots: z.array(z.string()).optional(),
    })
    .optional(),
});

export type Doc = z.infer<typeof DocSchema>;

export interface NavItem {
  title: string;
  href: string;
  external?: boolean;
  description?: string;
}

export interface NavSection {
  title: string;
  items: NavItem[];
}

/*
 * Sanitize and validate file path to prevent directory traversal attacks
 */
function sanitizeFilePath(inputPath: string): string {
  // Remove any path traversal attempts
  const sanitized = inputPath
    .replace(/\.\./g, "") // Remove ..
    .replace(/\/+/g, "/") // Normalize multiple slashes
    .replace(/^\/+/, "") // Remove leading slashes
    .replace(/\/+$/, ""); // Remove trailing slashes

  // Validate that the path only contains safe characters
  if (!/^[\w\-/.]*$/.test(sanitized)) {
    throw new Error("Invalid file path characters");
  }

  return sanitized;
}

/*
 * Validate slug format to prevent injection attacks
 */
function validateSlug(slug: string): string {
  const sanitized = slug.trim();

  // Basic validation
  if (sanitized.length > 100) {
    throw new Error("Slug too long");
  }

  // Allow only safe characters
  if (!/^[\w\-/]*$/.test(sanitized)) {
    throw new Error("Invalid slug format");
  }

  return sanitized;
}

/*
 * Extract title from H1 tag in markdown content
 */
function extractTitleFromH1(content: string): string | null {
  // Remove code blocks to avoid matching # inside them
  const contentWithoutCodeBlocks = content
    // Remove fenced code blocks (```...```)
    .replace(/```[\s\S]*?```/g, "")
    // Remove inline code blocks (`...`)
    .replace(/`[^`]+`/g, "");

  // Look for the first H1 tag in the cleaned content
  const h1Match = /^#\s+(.+)$/m.exec(contentWithoutCodeBlocks);
  if (h1Match && h1Match[1]) {
    // Clean up the title (remove extra whitespace, emoji, etc.)
    return h1Match[1]
      .trim()
      .replace(/^\W+|\W+$/g, "")
      .slice(0, 200);
  }
  return null;
}

/*
 * Read and parse MDX file with security validations
 */
async function readMdxFile(filePath: string, slug: string) {
  try {
    // Check file size limit (5MB)
    const stats = fs.statSync(filePath);
    if (stats.size > 5 * 1024 * 1024) {
      console.error(`File too large: ${filePath}`);
      return null;
    }

    const content = fs.readFileSync(filePath, "utf-8");

    // Basic content validation
    if (content.length > 1024 * 1024) {
      // 1MB content limit
      console.error(`Content too large: ${filePath}`);
      return null;
    }

    const { data: frontmatter, content: mdContent } = matter(content);

    // Try to get title from frontmatter first, then from H1 tag
    let title = frontmatter?.title;
    if (!title || typeof title !== "string") {
      title = extractTitleFromH1(mdContent);
      if (!title) {
        console.warn(`No valid title found in frontmatter or H1 for doc: ${slug}`);
        return null;
      }
    }

    // Sanitize frontmatter with extracted or existing title
    const sanitizedFrontmatter = {
      ...frontmatter,
      title: title.slice(0, 500), // Use extracted or frontmatter title
      description: frontmatter.description?.slice(0, 1000), // Optional and increased limit
      updatedAt: frontmatter.updatedAt,
      section: frontmatter.section || "core", // Provide default if missing
    };

    // For docs migration: return raw content for MDXRemote processing
    return {
      ...sanitizedFrontmatter,
      slug,
      content: mdContent, // Return raw MDX content instead of processed HTML
      lastModified: sanitizedFrontmatter?.updatedAt
        ? new Date(sanitizedFrontmatter.updatedAt)
        : new Date(),
      section: sanitizedFrontmatter.section ?? "core",
    };
  } catch (error) {
    console.error(`Error reading MDX file: ${filePath}`, error);
    return null;
  }
}

/*
 * Dynamic import helper for docs from root /docs directory
 */
async function importDocFromRootDocs(slug: string) {
  try {
    const sanitizedSlug = validateSlug(slug);
    const docsPath = path.join(process.cwd(), "docs");

    // Ensure the docs path exists and is accessible
    if (!fs.existsSync(docsPath)) {
      console.warn("Docs directory does not exist:", docsPath);
      return null;
    }

    // Try different file patterns - prefer .mdx over .md
    const patterns = [
      path.join(docsPath, `${sanitizedSlug}.mdx`),
      path.join(docsPath, `${sanitizedSlug}.md`),
      path.join(docsPath, sanitizedSlug, "index.mdx"),
      path.join(docsPath, sanitizedSlug, "index.md"),
    ];

    for (const filePath of patterns) {
      // Validate that the resolved path is within the docs directory
      const resolvedPath = path.resolve(filePath);
      const resolvedDocsPath = path.resolve(docsPath);
      if (!resolvedPath.startsWith(resolvedDocsPath)) {
        console.warn("Attempted directory traversal:", slug);
        continue;
      }

      if (fs.existsSync(filePath)) {
        return await readMdxFile(filePath, sanitizedSlug);
      }
    }

    return null;
  } catch (error) {
    console.error(`Error importing doc from root docs: ${slug}`, error);
    return null;
  }
}

