      })
      .slice(0, 20); // Limit search results

    return results;
  } catch (error) {
    console.error("Error searching docs:", error);
    return [];
  }
}

"use client";

import { useCallback, useEffect, useRef, useState } from "react";

export interface DocSearchResult {
  title: string;
  content: string;
  url: string;
  section?: string;
}

interface UseDocsSearchOptions {
  /**
   * Debounce delay in milliseconds
   * @default 300
   */
  debounceDelay?: number;
  /**
   * Minimum query length to trigger search
   * @default 2
   */
  minQueryLength?: number;
  /**
   * Maximum number of results to fetch
   * @default 10
   */
  limit?: number;
}

interface UseDocsSearchReturn {
  query: string;
  setQuery: (query: string) => void;
  results: DocSearchResult[];
  isLoading: boolean;
  error: string | null;
  search: (searchQuery?: string) => Promise<void>;
  clearResults: () => void;
  hasSearched: boolean;
}

/**
 * Hook for managing docs search functionality with debouncing and caching
 */
export function useDocsSearch(options: UseDocsSearchOptions = {}): UseDocsSearchReturn {
  const { debounceDelay = 300, minQueryLength = 2, limit = 10 } = options;

  const [query, setQuery] = useState("");
  const [results, setResults] = useState<DocSearchResult[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [hasSearched, setHasSearched] = useState(false);

  // Cache for search results
  const cacheRef = useRef(new Map<string, DocSearchResult[]>());
  const abortControllerRef = useRef<AbortController | null>(null);
  const debounceTimeoutRef = useRef<NodeJS.Timeout | null>(null);

  /**
   * Perform search API call
   */
  const performSearch = useCallback(
    async (searchQuery: string): Promise<DocSearchResult[]> => {
      // Check cache first
      const cacheKey = `${searchQuery.toLowerCase().trim()}_${limit}`;
      const cached = cacheRef.current.get(cacheKey);
      if (cached) {
        return cached;
      }

      // Cancel previous request
      if (abortControllerRef.current) {
        abortControllerRef.current.abort();
      }

      // Create new abort controller
      abortControllerRef.current = new AbortController();

      try {
        const response = await fetch("/api/docs/search", {
          method: "POST",
          headers: {
            "Content-Type": "application/json",
            Accept: "application/json",
          },
          body: JSON.stringify({
            query: searchQuery.trim(),
            limit,
          }),
          signal: abortControllerRef.current.signal,
        });

        if (!response.ok) {
          throw new Error(`Search failed: ${response.statusText}`);
        }

        const data = await response.json();
        const searchResults = data.results || [];

        // Cache the results
        cacheRef.current.set(cacheKey, searchResults);

        // Limit cache size to prevent memory issues
        if (cacheRef.current.size > 100) {
          const firstKey = cacheRef.current.keys().next().value;
          if (firstKey) {
            cacheRef.current.delete(firstKey);
          }
        }

        return searchResults;
      } catch (err) {
        if (err instanceof Error && err.name === "AbortError") {
          // Request was cancelled, don't treat as error
          throw err;
        }
        throw new Error(err instanceof Error ? err.message : "Search failed");
      }
    },
    [limit]
  );

  /**
   * Execute search with loading states and error handling
   */
  const search = useCallback(
    async (searchQuery?: string) => {
      const queryToSearch = searchQuery ?? query;

      if (!queryToSearch.trim() || queryToSearch.length < minQueryLength) {
        setResults([]);
        setError(null);
        setHasSearched(false);
        return;
      }

      setIsLoading(true);
      setError(null);

      try {
        const searchResults = await performSearch(queryToSearch);
        setResults(searchResults);
        setHasSearched(true);
      } catch (err) {
        if (err instanceof Error && err.name === "AbortError") {
          // Request was cancelled, don't update state
          return;
        }

        const errorMessage = err instanceof Error ? err.message : "Search failed";
        setError(errorMessage);
        setResults([]);
        setHasSearched(true);
      } finally {
        setIsLoading(false);
      }
    },
    [query, minQueryLength, performSearch]
  );

  /**
   * Clear search results and reset state
   */
  const clearResults = useCallback(() => {
    setQuery("");
    setResults([]);
    setError(null);
    setHasSearched(false);

    // Cancel any pending requests
    if (abortControllerRef.current) {
      abortControllerRef.current.abort();
    }

    // Clear debounce timeout
    if (debounceTimeoutRef.current) {
      clearTimeout(debounceTimeoutRef.current);
    }
  }, []);

  /**
   * Debounced search effect
   */
  useEffect(() => {
    if (debounceTimeoutRef.current) {
      clearTimeout(debounceTimeoutRef.current);
    }

    if (query.trim() && query.length >= minQueryLength) {
      debounceTimeoutRef.current = setTimeout(() => {
        void search(query);
      }, debounceDelay);
    } else {
      setResults([]);
      setError(null);
      setHasSearched(false);
    }

    return () => {
      if (debounceTimeoutRef.current) {
        clearTimeout(debounceTimeoutRef.current);
      }
    };
  }, [query, minQueryLength, debounceDelay, search]);

  /**
   * Cleanup on unmount
   */
  useEffect(() => {
    return () => {
      if (abortControllerRef.current) {
        abortControllerRef.current.abort();
      }
      if (debounceTimeoutRef.current) {
        clearTimeout(debounceTimeoutRef.current);
      }
    };
  }, []);

  return {
    query,
    setQuery,
    results,
    isLoading,
    error,
    search,
    clearResults,
    hasSearched,
  };
}

import { readdir, readFile } from "fs/promises";
import matter from "gray-matter";
import { join } from "path";

export interface DocSearchResult {
  title: string;
  content: string;
  url: string;
}

export class DocsSearchService {
  private static instance: DocsSearchService;
  private docsCache: Map<string, { content: string; metadata: any }> = new Map<
    string,
    { content: string; metadata: any }
  >();
  private initialized = false;

  private constructor() {
    this.docsCache = new Map<string, { content: string; metadata: any }>();
    this.initialized = false;
  }

  public static getInstance(): DocsSearchService {
    if (!DocsSearchService.instance) {
      DocsSearchService.instance = new DocsSearchService();
    }
    return DocsSearchService.instance;
  }

  private async initialize() {
    if (this.initialized) return;

    // Load docs from root /docs directory
    const rootDocsDir = join(process.cwd(), "docs");
    await this.loadDocFiles(rootDocsDir, "");

    if (this.docsCache.size === 0) {
      console.warn("DocsSearchService: No docs found in", rootDocsDir);
    }

    this.initialized = true;
  }

  /**
   * Force re-initialization (useful if docs were loaded after first access)
   */
  public reset() {
    this.docsCache.clear();
    this.initialized = false;
  }

  private async loadDocFiles(dir: string, baseReplacePath = "") {
    try {
      const entries = await readdir(dir, { withFileTypes: true });

      for (const entry of entries) {
        const fullPath = join(dir, entry.name);

        if (entry.isDirectory()) {
          await this.loadDocFiles(fullPath, baseReplacePath);
        } else if (entry.name.endsWith(".mdx") || entry.name.endsWith(".md")) {
          const content = await readFile(fullPath, "utf-8");
          const { data, content: mdContent } = matter(content);

          let relativePath: string;
          if (baseReplacePath) {
            // Legacy path processing
            relativePath = fullPath
              .replace(process.cwd(), "")
              .replace(baseReplacePath, "")
              .replace(/\.(mdx?|md)$/, "")
              .replace(/^\/+/, "");
          } else {
            // Root docs path processing
            relativePath = fullPath
              .replace(join(process.cwd(), "docs"), "")
              .replace(/\.(mdx?|md)$/, "")
              .replace(/^\/+/, "");
          }

          // Normalize index files: "getting-started/index" -> "getting-started"
          relativePath = relativePath.replace(/\/index$/, "");

          // Avoid duplicates - prefer root docs over legacy
          if (!this.docsCache.has(relativePath)) {
            this.docsCache.set(relativePath, {
              content: mdContent,
              metadata: data,
            });
          }
        }
      }
    } catch (error) {
      console.warn(`Warning: Could not load docs from ${dir}:`, error);
    }
  }

  public async search(query: string, limit = 5): Promise<DocSearchResult[]> {
    await this.initialize();

    const results: DocSearchResult[] = [];
    const searchTerms = query.toLowerCase().split(" ");

    for (const [path, { content, metadata }] of this.docsCache.entries()) {
      const contentLower = content.toLowerCase();
      const titleLower = (metadata.title ?? "").toLowerCase();

      // Simple relevance scoring
      let score = 0;
      for (const term of searchTerms) {
        if (titleLower.includes(term)) score += 2;
        if (contentLower.includes(term)) score += 1;
      }

      if (score > 0) {
        results.push({
          title: metadata.title ?? path,
          content: this.extractRelevantSnippet(content, query),
          url: `/docs/${path}`,
        });
      }
    }

    // Sort by relevance and limit results
    return results
      .sort((a, b) => {
        const scoreA = searchTerms.reduce(
          (acc, term) =>
            acc +
            (a.title.toLowerCase().includes(term) ? 2 : 0) +
            (a.content.toLowerCase().includes(term) ? 1 : 0),
          0
        );
        const scoreB = searchTerms.reduce(
          (acc, term) =>
            acc +
            (b.title.toLowerCase().includes(term) ? 2 : 0) +
            (b.content.toLowerCase().includes(term) ? 1 : 0),
          0
        );
        return scoreB - scoreA;
      })
      .slice(0, limit);
  }

  private extractRelevantSnippet(content: string, query: string): string {
    const searchTerms = query.toLowerCase().split(" ");
    const contentLower = content.toLowerCase();

    // Find the first occurrence of any search term
    let startIndex = -1;
    for (const term of searchTerms) {
      const index = contentLower.indexOf(term);
      if (index !== -1) {
        startIndex = index;
        break;
      }
    }

    if (startIndex === -1) {
      return `${content.slice(0, 150)}...`;
    }

    // Extract a snippet around the match
    const snippetStart = Math.max(0, startIndex - 75);
    const snippetEnd = Math.min(content.length, startIndex + 150);
    const snippet = content.slice(snippetStart, snippetEnd);

    return `${snippetStart > 0 ? "..." : ""}${snippet}${snippetEnd < content.length ? "..." : ""}`;
  }
}

import { NextResponse } from "next/server";
import { z } from "zod";
import { openai } from "@/lib/open-ai";
import { DocsSearchService } from "@/server/services/docs-search";
import { ErrorService } from "@/server/services/error-service";
import { rateLimitService, rateLimits } from "@/server/services/rate-limit-service";

// Sanitize input to prevent prompt injection
function sanitizeForPrompt(text: string): string {
  // Remove potential prompt injection patterns
  return (
    text
      // Remove instruction-like patterns that could manipulate the AI
      .replace(
        /\b(ignore|disregard|forget|override|bypass)\s+(previous|above|all|any)\s+(instructions?|prompts?|rules?)/gi,
        "[REDACTED]"
      )
      // Remove common prompt injection techniques
      .replace(/\b(system|assistant|user)\s*:/gi, "[ROLE]")
      // Remove potential command injections
      .replace(/```[^`]*```/g, "[CODE_BLOCK]")
      // Escape special characters that might be interpreted as markdown or special syntax
      .replace(/[<>]/g, "")
      // Limit consecutive newlines to prevent format manipulation
      .replace(/\n{3,}/g, "\n\n")
      // Trim excessive whitespace
      .trim()
  );
}

const searchRequestSchema = z.object({
  query: z.string().min(1, "Search query is required").max(500, "Search query is too long"),
  limit: z
    .number()
    .optional()
    .default(5)
    .refine((val) => val > 0 && val <= 20, {
      message: "Limit must be between 1 and 20",
    }),
});

export async function POST(req: Request) {
  try {
    // Extract client IP for rate limiting
    // Try to get IP from various headers in order of reliability
    const forwardedFor = req.headers.get("x-forwarded-for");
    const realIp = req.headers.get("x-real-ip");
    const cfConnectingIp = req.headers.get("cf-connecting-ip");

    // Use the first available IP address, with fallback to a generic identifier
    const clientIp = forwardedFor?.split(",")[0]?.trim() || realIp || cfConnectingIp || "anonymous";

    // Apply rate limiting with custom limits for AI search
    // More restrictive than regular search due to OpenAI API costs
    const aiSearchRateLimit = {
      requests: 10, // 10 requests
      duration: 60, // per minute
    };

    try {
      await rateLimitService.checkLimit(clientIp, "ai-docs-search", aiSearchRateLimit);
    } catch (error) {
      // If it's a rate limit error, return appropriate response
      if (ErrorService.isAppError(error) && error.code === "RATE_LIMITED") {
        return NextResponse.json(
          {
            error: "Too many requests",
            message: "You have exceeded the rate limit for AI search. Please try again later.",
            retryAfter: error.metadata?.reset,
          },
          {
            status: 429,
            headers: {
              "X-RateLimit-Limit": String(error.metadata?.limit || aiSearchRateLimit.requests),
              "X-RateLimit-Remaining": String(error.metadata?.remaining || 0),
              "X-RateLimit-Reset": String(error.metadata?.reset || 0),
              "Retry-After": String(
                Math.ceil(((error.metadata?.reset as number) || 0) - Date.now() / 1000)
              ),
            },
          }
        );
      }
      // Re-throw other errors
      throw error;
    }

    // Parse and validate the request body
    const body = await req.json().catch(() => ({}));
    const validationResult = searchRequestSchema.safeParse(body);

    if (!validationResult.success) {
      return NextResponse.json(
        {
          error: "Invalid request",
          details: validationResult.error.issues,
        },
        { status: 400 }
      );
    }

    const { query, limit } = validationResult.data;

    // Get current rate limit status for response headers
    const rateLimitStatus = await rateLimitService.getStatus(clientIp, "ai-docs-search");
    const rateLimitHeaders = {
      "X-RateLimit-Limit": String(rateLimitStatus.limit),
      "X-RateLimit-Remaining": String(rateLimitStatus.remaining),
      "X-RateLimit-Reset": String(rateLimitStatus.reset),
    };

    // Check if client wants JSON response
    const acceptHeader = req.headers.get("accept");
    if (acceptHeader?.includes("application/json")) {
      // Search documentation
      const searchService = DocsSearchService.getInstance();
      const searchResults = await searchService.search(query, limit);
      return NextResponse.json({ results: searchResults }, { headers: rateLimitHeaders });
    }

    // Search documentation for streaming response
    const searchService = DocsSearchService.getInstance();
    const searchResults = await searchService.search(query, limit);

    // If OpenAI isn't configured, fall back to returning JSON results
    if (!openai) {
      return NextResponse.json({ results: searchResults }, { headers: rateLimitHeaders });
    }

    // Generate streaming AI response
    const response = await openai.chat.completions.create({
      model: "gpt-4-turbo-preview",
      messages: [
        {
          role: "system",
          content: `You are a helpful documentation assistant for Shipkit.
          Your responses should be clear, concise, and focused on answering the user's question.
          Include relevant code examples when appropriate.
          Format your responses in markdown.

          Here are some relevant documentation snippets to help you answer:
          ${searchResults.map((result) => `### ${sanitizeForPrompt(result.title)}\n${sanitizeForPrompt(result.content)}`).join("\n\n")}`,
        },
        {
          role: "user",
          content: sanitizeForPrompt(query),
        },
      ],
      temperature: 0.7,
      max_tokens: 500,
      stream: true,
    });

    // Create a text encoder
    const encoder = new TextEncoder();

    // Create a readable stream from the OpenAI response
    const stream = new ReadableStream({
      async start(controller) {
        try {
          for await (const chunk of response) {
            const text = chunk.choices[0]?.delta?.content ?? "";
            if (text) {
              controller.enqueue(encoder.encode(text));
            }
          }
          controller.close();
        } catch (error) {
          controller.error(error);
        }
      },
    });

    // Return the stream with appropriate headers including rate limit info
    const headers = new Headers({
      "Content-Type": "text/plain; charset=utf-8",
      "Cache-Control": "no-cache",
      "Transfer-Encoding": "chunked",
      ...rateLimitHeaders,
    });

    return new Response(stream, { headers });
  } catch (error) {
    // Handle rate limit errors that weren't caught earlier
    if (ErrorService.isAppError(error) && error.code === "RATE_LIMITED") {
      return NextResponse.json(
        {
          error: "Too many requests",
          message: "You have exceeded the rate limit for AI search. Please try again later.",
          retryAfter: error.metadata?.reset,
        },
        {
          status: 429,
          headers: {
            "X-RateLimit-Limit": String(error.metadata?.limit || 10),
            "X-RateLimit-Remaining": String(error.metadata?.remaining || 0),
            "X-RateLimit-Reset": String(error.metadata?.reset || 0),
            "Retry-After": String(
              Math.ceil(((error.metadata?.reset as number) || 0) - Date.now() / 1000)
            ),
          },
        }
      );
    }

    console.error("Search error:", error);
    return NextResponse.json(
      {
        error: "Failed to process search request",
        details: error instanceof Error ? error.message : "Unknown error",
      },
      { status: 500 }
    );
  }
}
